const NAV=['Dashboard','MCQs','Simulations','Readings','Exam Mode','Missed Log','Calendar','System Health','Backup & Restore','Dark Mode'];
const AREA_VIEWS=['Dashboard','MCQs','Simulations','Readings'];
const $=id=>document.getElementById(id);
let state=JSON.parse(localStorage.getItem(STORAGE_KEY)||'null')||{section:'ethics',view:'Dashboard',dark:false,answered:{},missed:{},progress:{},seen:{},currentQuiz:[],quizIndex:0,examDate:'',simResponses:{}};
function save(){localStorage.setItem(STORAGE_KEY,JSON.stringify(state));}
function today(){return new Date().toISOString().slice(0,10);}
function logActivity(type,sec,detail){let d=today();state.progress[d]=state.progress[d]||[];state.progress[d].push({time:new Date().toLocaleTimeString(),type,sec,detail});save();}
function shuffle(a){return [...a].sort(()=>Math.random()-.5)}
function pct(n,d){return d?Math.round(n/d*100):0}
function sectionName(id){return SECTIONS.find(s=>s.id===id).name}
function render(){document.body.classList.toggle('dark',!!state.dark);renderSections();renderNav();let v=state.view;if(v==='Dashboard')dashboard();else if(v==='MCQs')mcqs();else if(v==='Simulations')sims();else if(v==='Readings')readings();else if(v==='Exam Mode')exam();else if(v==='Missed Log')missed();else if(v==='Calendar')calendar();else if(v==='System Health')health();else if(v==='Backup & Restore')backup();}
function renderSections(){let active=AREA_VIEWS.includes(state.view);$('sections').innerHTML=SECTIONS.map(s=>`<button ${active?'':'disabled'} class="${state.section===s.id&&active?'active':''}" onclick="state.section='${s.id}';state.currentQuiz=[];state.quizIndex=0;save();render()"><span class="pill">Area ${s.roman}</span><br>${s.name}<br><span class="muted small">${s.weight}</span></button>`).join('');}
function renderNav(){$('nav').innerHTML=NAV.map(v=>`<button class="${state.view===v?'active':''}" onclick="${v==='Dark Mode'?'toggleDark()':`state.view='${v}';save();render()`}">${v}</button>`).join('');}
function toggleDark(){state.dark=!state.dark;save();render();}
function dashboard(){let ans=Object.values(state.answered),cor=ans.filter(a=>a.correct).length;let areaQs=QUESTIONS.filter(q=>q.sec===state.section);let seen=(state.seen[state.section]||[]).length;$('app').innerHTML=`<div class="card hero"><h2>CPA AUD Command Center</h2><div class="grid"><div><b>Running Score</b><div class="metric">${pct(cor,ans.length)}%</div><p class="muted">Based on attempted MCQs.</p></div><div><b>Current Area Pool</b><div class="metric">${areaQs.length}</div><p class="muted">Original CPA-style MCQs.</p></div><div><b>Seen in Area</b><div class="metric">${seen}</div><p class="muted">Non-repeat rotation active.</p></div><div><b>TBS Pool</b><div class="metric">${SIMS.filter(s=>s.sec===state.section).length}</div><p class="muted">Expanded simulations.</p></div></div></div><div class="card"><h3>Version 8.2.0 Content Changes</h3><p>MCQ pool expanded to ${QUESTIONS.length} questions. Simulations expanded to ${SIMS.length} TBSs. Readings now include topic-specific rules, traps, examples, and memory aids.</p><p><b>Rotation rule:</b> a 20-question quiz pulls never-seen questions first. Repeats are blocked until the area pool is exhausted or you manually reset question history.</p></div>`;}
function getNextQuiz(sec,n){let seen=new Set(state.seen[sec]||[]), pool=QUESTIONS.filter(q=>q.sec===sec), unused=shuffle(pool.filter(q=>!seen.has(q.id))); if(unused.length<n){ if(unused.length===0){state.seen[sec]=[]; return shuffle(pool).slice(0,n);} return unused.concat(shuffle(pool.filter(q=>seen.has(q.id))).slice(0,n-unused.length));} return unused.slice(0,n);}
function startQuiz(n){state.currentQuiz=getNextQuiz(state.section,n).map(q=>q.id);state.quizIndex=0;logActivity('MCQ Quiz',state.section,`Started ${n} questions with non-repeat rotation`);render();}
function resetHistory(){if(confirm('Reset seen-question history for this area?')){state.seen[state.section]=[];state.currentQuiz=[];state.quizIndex=0;save();render();}}
function mcqs(){if(!state.currentQuiz.length){let seen=(state.seen[state.section]||[]).length,total=QUESTIONS.filter(q=>q.sec===state.section).length;$('app').innerHTML=`<div class="card hero"><h2>MCQs - ${sectionName(state.section)}</h2><p>Non-repeat rotation is active. You should receive a fresh set on the next 20-question quiz until this area is exhausted.</p><p><span class="pill">Seen: ${seen} / ${total}</span><span class="pill">Remaining before repeats: ${Math.max(total-seen,0)}</span></p><div class="actions"><button class="primary" onclick="startQuiz(20)">Start 20 Questions</button><button onclick="startQuiz(39)">Start 39 Questions</button><button class="warn" onclick="resetHistory()">Reset Question History</button></div></div>`;return;} let id=state.currentQuiz[state.quizIndex],q=QUESTIONS.find(x=>x.id===id), answered=state.answered[id];$('app').innerHTML=`<div class="card"><p class="muted">Question ${state.quizIndex+1} of ${state.currentQuiz.length} · ${q.topic} · ${q.difficulty}</p><h3>${q.q}</h3>${q.choices.map((c,i)=>`<button class="choice ${answered?(('ABCD'[i]===q.ans)?'correct':(answered.choice==='ABCD'[i]?'wrong':'')):''}" ${answered?'disabled':''} onclick="answerQ('${q.id}','${'ABCD'[i]}')">${'ABCD'[i]}. ${c}</button>`).join('')}${answered?`<div class="card"><b>Explanation</b><p>${q.exp}</p></div>`:''}<div class="actions"><button ${state.quizIndex===0?'disabled':''} onclick="state.quizIndex--;save();render()">Previous</button><button ${state.quizIndex>=state.currentQuiz.length-1?'disabled':''} onclick="state.quizIndex++;save();render()">Next</button><button onclick="state.currentQuiz=[];state.quizIndex=0;save();render()">End Block</button></div></div>`;}
function answerQ(id,ch){let q=QUESTIONS.find(x=>x.id===id),correct=ch===q.ans;state.answered[id]={choice:ch,correct,date:today()};state.seen[q.sec]=Array.from(new Set([...(state.seen[q.sec]||[]),id]));if(!correct)state.missed[id]={date:today(),topic:q.topic,sec:q.sec};logActivity('MCQ Answer',q.sec,`${id} ${correct?'correct':'missed'}`);render();}
function readings(){let rs=READINGS.filter(r=>r.sec===state.section);$('app').innerHTML=`<div class="card hero"><h2>Readings - ${sectionName(state.section)}</h2><p>Expanded topic-specific rules, examples, and CPA traps.</p></div>${rs.map(r=>`<div class="card"><h3>${r.title}</h3><h4>Key rules</h4><p>${r.keyRules}</p><h4>Common CPA trap</h4><p>${r.trap}</p><h4>Exam example</h4><p>${r.example}</p><p><b>${r.memory}</b></p></div>`).join('')}`;}
function sims(){let ss=SIMS.filter(s=>s.sec===state.section);$('app').innerHTML=`<div class="card hero"><h2>Simulations - ${sectionName(state.section)}</h2><p>Expanded TBS pool with exhibits and hidden self-check rubrics.</p></div>${ss.map(s=>`<div class="card"><h3>${s.title}</h3><p><span class="pill">${s.difficulty}</span></p><p>${s.scenario}</p><details><summary>Open Exhibits</summary>${s.exhibits.map(e=>`<div class="card"><b>${e.name}</b><p>${e.text}</p></div>`).join('')}</details><ol>${s.tasks.map(t=>`<li>${t}</li>`).join('')}</ol><textarea id="resp-${s.id}" placeholder="Enter your response">${state.simResponses[s.id]||''}</textarea><div class="actions"><button class="primary" onclick="saveSim('${s.id}')">Save Response</button><button onclick="toggleRubric('${s.id}')" id="btn-${s.id}">Show Rubric</button></div><div class="card rubric" id="rub-${s.id}"><b>Self-check rubric</b><ul>${s.rubric.map(r=>`<li>${r}</li>`).join('')}</ul></div></div>`).join('')}`;}
function saveSim(id){state.simResponses[id]=$('resp-'+id).value;logActivity('TBS Response',state.section,id);render();}
function toggleRubric(id){let el=$('rub-'+id),btn=$('btn-'+id);el.classList.toggle('open');btn.textContent=el.classList.contains('open')?'Hide Rubric':'Show Rubric';}
function exam(){$('app').innerHTML=`<div class="card hero"><h2>Exam Mode</h2><p>MCQs appear before TBS simulations. Use this for flow testing.</p><div class="actions"><button class="primary" onclick="startExam('sample')">Sample Test</button><button onclick="startExam('partial')">Partial Exam</button><button onclick="startExam('full')">Full Exam Set</button></div></div>`;}
function startExam(mode){let n=mode==='sample'?20:mode==='partial'?39:78;state.view='MCQs';state.currentQuiz=shuffle(QUESTIONS).slice(0,n).map(q=>q.id);state.quizIndex=0;logActivity('Exam Mode','all',mode);save();render();}
function missed(){let ids=Object.keys(state.missed);$('app').innerHTML=`<div class="card hero"><h2>Missed Log</h2><p>${ids.length} missed questions captured.</p></div>${ids.map(id=>{let q=QUESTIONS.find(x=>x.id===id);return `<div class="card"><b>${id} · ${q.topic}</b><p>${q.q}</p><p class="muted">Correct answer: ${q.ans}. ${q.exp}</p></div>`}).join('')}`;}
function calendar(){$('app').innerHTML=`<div class="card hero"><h2>Calendar</h2><p>Exam date is blank until you set it.</p><input type="date" value="${state.examDate||''}" onchange="state.examDate=this.value;save();render()"><p>${state.examDate?`Days remaining: ${Math.ceil((new Date(state.examDate)-new Date())/86400000)}`:''}</p></div>`;}
function health(){let ids=QUESTIONS.map(q=>q.id),dups=ids.length-new Set(ids).size;$('app').innerHTML=`<div class="card hero"><h2>System Health</h2><table><tr><td>Version</td><td>${APP_VERSION}</td></tr><tr><td>MCQs</td><td>${QUESTIONS.length}</td></tr><tr><td>Duplicate MCQ IDs</td><td>${dups}</td></tr><tr><td>Simulations</td><td>${SIMS.length}</td></tr><tr><td>Reading Topics</td><td>${READINGS.length}</td></tr><tr><td>Storage Key</td><td>${STORAGE_KEY}</td></tr><tr><td>Non-repeat rotation</td><td>Enabled</td></tr></table></div>`;}
function backup(){$('app').innerHTML=`<div class="card hero"><h2>Backup & Restore</h2><button class="primary" onclick="exportProgress()">Export Progress</button> <button class="danger" onclick="if(confirm('Reset all progress?')){localStorage.removeItem(STORAGE_KEY);location.reload();}">System Reset</button><p class="muted">Export filename: aud-v8-2-0-progress.json</p></div>`;}
function exportProgress(){let blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='aud-v8-2-0-progress.json';a.click();}
render();
